      <Route path="/terms" component={Home} />
      <Route path="/cookies" component={Home} />
      <Route path="/gdpr" component={Home} />
      <Route path="/learn" component={Home} />
      <Route path="/subscribe/:tier" component={Packages} />
      <Route component={NotFound} />
    </Switch>
  );
}

function App() {
  return (
    <QueryClientProvider client={queryClient}>
      <ThemeProvider>
        <RouteAnalyticsProvider>
          <TooltipProvider>
            <Header />
            <Toaster />
            <URLMonitor />
            <URLBackupSystem />
            <Router />
            <Footer />
          </TooltipProvider>
        </RouteAnalyticsProvider>
      </ThemeProvider>
    </QueryClientProvider>
  );
}

export default App;

client/src/index.css.content:
@tailwind base;
@tailwind components;
@tailwind utilities;

/* CSS Variables for Theming */
:root {
  /* Light Theme Defaults */
  --bg-color-primary: hsl(0, 0%, 96.1%);
  --text-color-primary: hsl(0, 0%, 11.4%);
  --text-color-secondary: hsl(0, 0%, 25.9%);
  --primary-blue: hsl(207, 90%, 54%);
  --header-bg: hsla(0, 0%, 100%, 0.9);
  --header-border: hsl(0, 0%, 91%);
  --card-bg: hsl(0, 0%, 100%);
  --card-border: hsl(0, 0%, 91%);
  --muted-text: hsl(0, 0%, 43.1%);
  --code-bg: hsl(0, 0%, 94.1%);
  --code-text: hsl(0, 0%, 11.4%);
  --button-secondary-bg: hsl(0, 0%, 94.1%);
  --button-secondary-border: hsl(0, 0%, 86.3%);
  --button-secondary-hover-bg: hsl(0, 0%, 91%);
  --button-secondary-hover-text: hsl(0, 0%, 11.4%);
  --hero-h2-color: hsl(0, 0%, 11.4%);
  --vault-cyan: hsl(187, 100%, 42%);
  --vault-orange: hsl(36, 100%, 50%);
  --hyper-background-blend: hsla(187, 100%, 42%, 0.05);
  --hyper-primary-color: hsl(187, 100%, 42%);
  --hyper-text-color: hsl(187, 100%, 42%);
  --mindlift-purple: hsl(249, 80%, 67%);
  --mindlift-accent: hsl(249, 60%, 73%);

  /* shadcn/ui variables */
  --background: hsl(0, 0%, 100%);
  --foreground: hsl(20, 14.3%, 4.1%);
  --muted: hsl(60, 4.8%, 95.9%);
  --muted-foreground: hsl(25, 5.3%, 44.7%);
  --popover: hsl(0, 0%, 100%);
  --popover-foreground: hsl(20, 14.3%, 4.1%);
  --card: hsl(0, 0%, 100%);
  --card-foreground: hsl(20, 14.3%, 4.1%);
  --border: hsl(20, 5.9%, 90%);
  --input: hsl(20, 5.9%, 90%);
  --primary: hsl(207, 90%, 54%);
  --primary-foreground: hsl(211, 100%, 99%);
  --secondary: hsl(60, 4.8%, 95.9%);
  --secondary-foreground: hsl(24, 9.8%, 10%);
  --accent: hsl(60, 4.8%, 95.9%);
  --accent-foreground: hsl(24, 9.8%, 10%);
